### Tool class — `ApiTools.cs`

```csharp
using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Get a user by ID from the REST API.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID to look up")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var json = await httpClient.GetStringAsync(
            $"https://jsonplaceholder.typicode.com/users/{userId}", cancellationToken);
        return json;
    }

    [McpServerTool, Description("List all posts by a given user.")]
    public async Task<string> GetUserPosts(
        [Description("The user ID whose posts to retrieve")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching posts for user {UserId}", userId);
        var json = await httpClient.GetStringAsync(
            $"https://jsonplaceholder.typicode.com/posts?userId={userId}", cancellationToken);
        return json;
    }

    [McpServerTool(ReadOnly = true), Description("Search posts by keyword in the title.")]
    public async Task<string> SearchPosts(
        [Description("Keyword to search for in post titles")] string keyword,
        CancellationToken cancellationToken = default)
    {
        var json = await httpClient.GetStringAsync(
            "https://jsonplaceholder.typicode.com/posts", cancellationToken);
        var posts = JsonSerializer.Deserialize<JsonElement>(json);
        var matches = posts.EnumerateArray()
            .Where(p => p.GetProperty("title").GetString()!
                .Contains(keyword, StringComparison.OrdinalIgnoreCase))
            .Select(p => p.ToString());
        return $"[{string.Join(",", matches)}]";
    }
}
```

### `Program.cs` — stdio transport

```csharp
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: log to stderr only — stdout is the JSON-RPC transport
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient();   // registers IHttpClientFactory + HttpClient

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();        // discovers all [McpServerToolType] classes

await builder.Build().RunAsync();
```

---

### How DI works for MCP tools

The SDK uses two injection styles, and you can mix them:

| Style | How it works |
|-------|-------------|
| **Constructor injection** (non-static class) | Services like `HttpClient`, `ILogger<T>` are injected via the primary constructor. The class is resolved from the DI container per invocation. This is what `ApiTools` above uses. |
| **Method parameter injection** (static class) | DI services can appear directly as method parameters. The SDK detects registered services and injects them — they **never** appear in the tool's JSON schema sent to the LLM. |

**Key rule:** The framework automatically distinguishes between *tool parameters* (shown to the LLM) and *injected services* (`CancellationToken`, `ILogger<T>`, `HttpClient`, `IMcpServer`, `IProgress<T>`, etc.) — injected types are hidden from the schema.

Register your services in `Program.cs` before `AddMcpServer()`, and the SDK handles the rest.
